"use client";
import { useState } from "react";
import { useRouter } from "next/navigation";

export default function LoginPage() {
    const [role, setRole] = useState("reader");
    const router = useRouter();

    const handleLogin = (e) => {
        e.preventDefault();
        const routes = { reader: "/dashboard", librarian: "/librarian", admin: "/admin" };
        router.push(routes[role]);
    };

    return (
        <div className="auth-page">
            <div className="auth-card">
                <h2>Вход в систему</h2>
                <p className="auth-subtitle">БиблиотекаБудущего</p>
                <form onSubmit={handleLogin} className="auth-form">
                    <label><span>Email</span><input type="email" placeholder="name@example.com" required /></label>
                    <label><span>Пароль</span><input type="password" placeholder="••••••••" required /></label>
                    <label><span>Роль (для демо)</span>
                        <select value={role} onChange={e => setRole(e.target.value)}>
                            <option value="reader">👤 Читатель</option>
                            <option value="librarian">📖 Библиотекарь</option>
                            <option value="admin">⚙️ Администратор</option>
                        </select>
                    </label>
                    <button type="submit" className="btn btn-primary btn-block">Войти</button>
                </form>
                <a href="/catalog" className="auth-link">Продолжить как гость →</a>
            </div>
        </div>
    );
}